import React, { useState, useEffect } from 'react';
import './CookieBanner.css';

export default function CookieBanner() {
  const [visible, setVisible] = useState(false);
  const [showDetails, setShowDetails] = useState(false);
  const [preferences, setPreferences] = useState({
    necessary: true,
    analytics: false,
    marketing: false,
    functional: false,
  });

  useEffect(() => {
    const consent = localStorage.getItem('ame_cookie_consent');
    if (!consent) {
      const timer = setTimeout(() => setVisible(true), 800);
      return () => clearTimeout(timer);
    }
  }, []);

  const saveConsent = (type, prefs) => {
    localStorage.setItem(
      'ame_cookie_consent',
      JSON.stringify({ type, prefs, date: new Date().toISOString() })
    );
    setVisible(false);
  };

  const handleAcceptAll = () => {
    const all = { necessary: true, analytics: true, marketing: true, functional: true };
    setPreferences(all);
    saveConsent('all', all);
  };

  const handleRejectAll = () => {
    const minimal = { necessary: true, analytics: false, marketing: false, functional: false };
    setPreferences(minimal);
    saveConsent('necessary', minimal);
  };

  const handleSavePreferences = () => {
    saveConsent('custom', preferences);
  };

  const toggle = (key) => {
    if (key === 'necessary') return;
    setPreferences((prev) => ({ ...prev, [key]: !prev[key] }));
  };

  if (!visible) return null;

  return (
    <div className={`cookie-banner ${visible ? 'cookie-banner--visible' : ''}`}>
      <div className="cookie-banner__inner">

        {/* Header */}
        <div className="cookie-banner__header">
          <div className="cookie-banner__icon">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
              <circle cx="12" cy="12" r="10" />
              <line x1="12" y1="8" x2="12" y2="12" />
              <line x1="12" y1="16" x2="12.01" y2="16" />
            </svg>
          </div>
          <span className="cookie-banner__title">Política de Privacidade &amp; Cookies</span>
          <span className="cookie-banner__badge">LGPD</span>
        </div>

        {/* Body */}
        {!showDetails ? (
          <div className="cookie-banner__body">
            <p className="cookie-banner__text">
              Utilizamos cookies e tecnologias similares para garantir o funcionamento do site,
              analisar o desempenho, personalizar conteúdo e melhorar sua experiência. Suas informações
              são tratadas de acordo com a <strong>Lei Geral de Proteção de Dados (LGPD — Lei nº 13.709/2018)</strong>.
              Você pode aceitar todos os cookies, recusar os não essenciais ou personalizar suas preferências.
            </p>

            <div className="cookie-banner__types">
              {[
                {
                  label: 'Essenciais',
                  desc: 'Necessários para o funcionamento básico do site. Não podem ser desativados.',
                  always: true,
                },
                {
                  label: 'Analíticos',
                  desc: 'Nos ajudam a entender como os visitantes interagem com o site (Google Analytics).',
                  always: false,
                },
                {
                  label: 'Funcionais',
                  desc: 'Permitem funcionalidades aprimoradas como chat e formulários inteligentes.',
                  always: false,
                },
                {
                  label: 'Marketing',
                  desc: 'Utilizados para exibir anúncios relevantes e medir campanhas publicitárias.',
                  always: false,
                },
              ].map(({ label, desc, always }) => (
                <div key={label} className="cookie-banner__type-item">
                  <div className="cookie-banner__type-info">
                    <span className="cookie-banner__type-label">{label}</span>
                    <span className="cookie-banner__type-desc">{desc}</span>
                  </div>
                  {always && <span className="cookie-banner__always">Sempre ativo</span>}
                </div>
              ))}
            </div>

            <button
              className="cookie-banner__details-btn"
              onClick={() => setShowDetails(true)}
            >
              Personalizar preferências
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <polyline points="9 18 15 12 9 6" />
              </svg>
            </button>
          </div>
        ) : (
          <div className="cookie-banner__body">
            <p className="cookie-banner__text">
              Gerencie suas preferências de cookies abaixo. Os cookies essenciais não podem ser desativados
              pois são necessários para o funcionamento do site.
            </p>

            <div className="cookie-banner__toggles">
              {[
                {
                  key: 'necessary',
                  label: 'Cookies Essenciais',
                  desc: 'Sessão, segurança e preferências básicas do site.',
                },
                {
                  key: 'analytics',
                  label: 'Cookies Analíticos',
                  desc: 'Google Analytics para métricas de tráfego e comportamento.',
                },
                {
                  key: 'functional',
                  label: 'Cookies Funcionais',
                  desc: 'Recursos de chat ao vivo, formulários e integrações.',
                },
                {
                  key: 'marketing',
                  label: 'Cookies de Marketing',
                  desc: 'Rastreamento para anúncios e campanhas de retargeting.',
                },
              ].map(({ key, label, desc }) => (
                <div key={key} className="cookie-toggle">
                  <div className="cookie-toggle__info">
                    <span className="cookie-toggle__label">{label}</span>
                    <span className="cookie-toggle__desc">{desc}</span>
                  </div>
                  <button
                    className={`cookie-toggle__switch ${preferences[key] ? 'cookie-toggle__switch--on' : ''} ${key === 'necessary' ? 'cookie-toggle__switch--disabled' : ''}`}
                    onClick={() => toggle(key)}
                    aria-pressed={preferences[key]}
                    disabled={key === 'necessary'}
                  >
                    <span className="cookie-toggle__thumb" />
                  </button>
                </div>
              ))}
            </div>

            <button
              className="cookie-banner__details-btn"
              onClick={() => setShowDetails(false)}
            >
              <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <polyline points="15 18 9 12 15 6" />
              </svg>
              Voltar ao resumo
            </button>
          </div>
        )}

        {/* Actions */}
        <div className="cookie-banner__actions">
          <button className="cookie-banner__btn cookie-banner__btn--reject" onClick={handleRejectAll}>
            Rejeitar não essenciais
          </button>

          {showDetails && (
            <button className="cookie-banner__btn cookie-banner__btn--save" onClick={handleSavePreferences}>
              Salvar preferências
            </button>
          )}

          <button className="cookie-banner__btn cookie-banner__btn--accept" onClick={handleAcceptAll}>
            Aceitar todos
          </button>
        </div>

        <p className="cookie-banner__footer">
          Ao continuar navegando, você concorda com nossa{' '}
          <a href="/politica-de-privacidade" target="_blank" rel="noopener noreferrer">
            Política de Privacidade
          </a>{' '}
          e nossos{' '}
          <a href="/termos-de-uso" target="_blank" rel="noopener noreferrer">
            Termos de Uso
          </a>.
          AME Engenharia Industrial — CNPJ 00.000.000/0001-00.
        </p>
      </div>
    </div>
  );
}
